import fs from "node:fs";
import path from "node:path";

let cachedRoot: string | null = null;

/**
 * Encontra a raiz do monorepo subindo a partir do diretório atual até achar o
 * package.json que declara "workspaces". Funciona tanto rodando os scripts do
 * core (cwd = packages/core) quanto o app web (cwd = apps/web).
 */
export function repoRoot(): string {
  if (cachedRoot) return cachedRoot;
  let dir = process.cwd();
  for (let i = 0; i < 8; i++) {
    const pkgPath = path.join(dir, "package.json");
    if (fs.existsSync(pkgPath)) {
      try {
        const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
        if (pkg.workspaces) {
          cachedRoot = dir;
          return dir;
        }
      } catch {
        // ignora package.json inválido e continua subindo
      }
    }
    const parent = path.dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  cachedRoot = process.cwd();
  return cachedRoot;
}

/** Diretório de dados compartilhados (na raiz do monorepo). */
export function dataDir(): string {
  return path.join(repoRoot(), "data");
}

/** Caminho do arquivo de embeddings gerado pela ingestão. */
export function knowledgePath(): string {
  return path.join(dataDir(), "knowledge.json");
}

/** Diretório com os HTMLs oficiais das normas. */
export function rawLawsDir(): string {
  return path.join(dataDir(), "laws-raw");
}
